    """Logarithmic integral li(x) = integral from 0 to x of dt/ln(t)."""
    if x <= 0:
        return float('-inf')
    if x == 1:
        return float('-inf')
    # Use series expansion: li(x) = Ei(ln(x)) where Ei is exponential integral
    # For practical purposes, use the approximation
    lnx = math.log(x)
    # li(x) ≈ x/ln(x) * sum_{k=0}^{N} k!/ln(x)^k
    result = 0
    term = 1.0
    for k in range(50):
        result += term
        term *= (k + 1) / lnx
        if abs(term) < 1e-15 * abs(result):
            break
    result *= x / lnx
    # Euler-Mascheroni correction
    result += 0.5772156649015329 + math.log(abs(lnx))
    return result

